TypeAdapter<?> typeAdapter = constructorConstructor.get(TypeToken.get(typeAdapterClass)).construct();

if (typeAdapter == null) {

throw new IllegalArgumentException("TypeAdapter " + typeAdapterClass + " must not be null.");

}

return typeAdapter;

}

else if (TypeAdapterFactory.class.isAssignableFrom(annotation.value())) {

