if (typeAdapterFactory2 == null) {

throw new IllegalArgumentException("TypeAdapterFactory " + typeAdapterFactory + " must not be null.");

}

return typeAdapterFactory2.create(gson, fieldType);

}

else {

throw new IllegalArgumentException("@JsonAdapter value must be TypeAdapter or TypeAdapterFactory reference.");

}

